def compute_baseline_labour_productivity_growth(ctx=None, *, inputs=None) -> Records:
    """Compute the projected annual labour productivity growth rates in the baseline scenario.

    Returns a series of labour productivity growth rates for the baseline scenario from 2009 to 2099.
    Each record corresponds to a year in the Baseline sheet row 12, columns D through CP.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: The calendar year of the productivity growth observation.
                - OBS_VALUE: The projected annual labour productivity growth rate for the given year.
            Optional record fields:
                - UNIT_MEASURE: The unit of measure for the productivity growth rate, expressed as percentage change in GDP. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Baseline!D12:CP12
        Layout: series
        Value type: float

    Examples:
        compute_baseline_labour_productivity_growth(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_BASELINE_LABOUR_PRODUCTIVITY_GROWTH:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

