def compute_baseline_gdp_deflator_growth(ctx=None, *, inputs=None) -> Records:
    """Compute the baseline GDP deflator growth series from the Baseline sheet.

    Returns the projected annual GDP deflator growth rates used in the baseline nominal GDP decomposition.
    Each record represents one annual observation, where TIME_PERIOD maps to a column header in the data range and OBS_VALUE is the corresponding cell value.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: The calendar year for the projected GDP deflator growth rate.
                - OBS_VALUE: The projected GDP deflator growth rate for the given year.
            Optional record fields:
                - UNIT_MEASURE: The measurement unit for the growth rate. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Baseline!D14:CP14
        Layout: series
        Value type: float

    Examples:
        compute_baseline_gdp_deflator_growth(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_BASELINE_GDP_DEFLATOR_GROWTH:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

