def compute_scenario_debt_to_gdp(ctx=None, *, inputs=None) -> Records:
    """Return the projected debt-to-GDP ratio for each climate scenario by year.

    Returns scenario-specific debt-to-GDP trajectories computed from the Output Scenarios worksheet.
    Each record maps to a single matrix cell where a scenario label from column B meets a year column header.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - SCENARIO: Identifies the climate scenario path (e.g. Paris, Moderate, Hot).
                - TIME_PERIOD: Projection year for the reported debt-to-GDP ratio.
                - OBS_VALUE: Debt-to-GDP ratio (percent of GDP) under the specified scenario and year.
            Optional record fields:
                - UNIT_MEASURE: Denotes the observation as a percent of GDP. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Output Scenarios!V111:CO116
        Layout: matrix
        Value type: float

    Examples:
        compute_scenario_debt_to_gdp(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_DEBT_TO_GDP:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

