def compute_scenario_debt_stabilizing_primary_balance(ctx=None, *, inputs=None) -> Records:
    """Compute the debt-stabilizing primary balance for the Paris climate scenario.

    Returns the primary balance, as a percent of GDP, needed to stabilize debt in the Paris scenario for each projection year.
    Each record corresponds to a single cell in the Paris output range, where the column header provides the time period and the cell value gives the primary balance.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Projection year.
                - OBS_VALUE: Debt-stabilizing primary balance (percent of GDP) for the given year in the Paris climate scenario.
            Optional record fields:
                - UNIT_MEASURE: Unit of measure for the observation value. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Paris!D36:CP36
        Layout: series
        Value type: float

    Examples:
        compute_scenario_debt_stabilizing_primary_balance(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_DEBT_STABILIZING_PRIMARY_BALANCE_PARIS:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

