def compute_scenario_debt_stabilizing_primary_balance(ctx=None, *, inputs=None) -> Records:
    """Compute the debt-stabilizing primary balance for the Moderate climate scenario.

    Return the annual primary balance required to stabilize the debt-to-GDP ratio under the Moderate climate scenario projections.
    Each record corresponds to a column in the Moderate sheet for a given year, binding TIME_PERIOD from the column header and OBS_VALUE from row 36.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the projection.
                - OBS_VALUE: Debt-stabilizing primary balance as a percentage of GDP.
            Optional record fields:
                - UNIT_MEASURE: Unit for the observation value. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Moderate!D36:CP36
        Layout: series
        Value type: float

    Examples:
        compute_scenario_debt_stabilizing_primary_balance(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_DEBT_STABILIZING_PRIMARY_BALANCE_MODERATE:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

