def compute_scenario_debt_stabilizing_primary_balance(ctx=None, *, inputs=None) -> Records:
    """Compute the debt-stabilizing primary balance for the Hot unadapted scenario.

    Returns the primary balance needed to stabilize the debt-to-GDP ratio over time under the Hot unadapted climate scenario.
    Each record corresponds to a cell in the source workbook range, with the observation value read from the cell.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: The year of the projection.
                - OBS_VALUE: The debt-stabilizing primary balance expressed as a percentage of GDP.
            Optional record fields:
                - UNIT_MEASURE: The unit of measurement for the observation value. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Hot Unadapted!D36:CP36
        Layout: series
        Value type: float

    Examples:
        compute_scenario_debt_stabilizing_primary_balance(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_DEBT_STABILIZING_PRIMARY_BALANCE_HOT_UNADAPTED:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

