def compute_scenario_nominal_gdp_growth(ctx=None, *, inputs=None) -> Records:
    """Compute annual nominal GDP growth for the Hot climate scenario.

    Returns a series of annual nominal GDP growth rates under the Hot scenario.
    Each record corresponds to one cell in the 'Hot' worksheet row 11, starting from column D.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the observation.
                - OBS_VALUE: Annual nominal GDP growth rate in percent.
            Optional record fields:
                - UNIT_MEASURE: Unit of measure for the observation value, expressed as a percentage of GDP. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Hot!D11:CP11
        Layout: series
        Value type: float

    Examples:
        compute_scenario_nominal_gdp_growth(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_NOMINAL_GDP_GROWTH_HOT:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

