def compute_scenario_nominal_gdp_growth(ctx=None, *, inputs=None) -> Records:
    """Compute projected nominal GDP growth rates for the Hot unadapted climate scenario.

    Returns a series of annual nominal GDP growth rates from the Hot Unadapted scenario projection worksheet.
    Each record corresponds to one cell in the 'Hot Unadapted' worksheet, pairing a year header with the observed growth rate value.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the projection.
                - OBS_VALUE: Annual nominal GDP growth rate for the given year and scenario.
            Optional record fields:
                - UNIT_MEASURE: Unit of the observation value. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Hot Unadapted!D11:CP11
        Layout: series
        Value type: float

    Examples:
        compute_scenario_nominal_gdp_growth(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_NOMINAL_GDP_GROWTH_HOT_UNADAPTED:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

