def compute_scenario_primary_expenditure_pct_gdp(ctx=None, *, inputs=None) -> Records:
    """Compute the annual primary expenditure as a percentage of GDP for a climate scenario.

    Returns a time series of primary‑expenditure‑to‑GDP ratios derived from the workbook scenario shard.
    Each record corresponds to one year column in the scenario output row.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the projection.
                - OBS_VALUE: Primary expenditure expressed as a percentage of GDP in that year.
            Optional record fields:
                - UNIT_MEASURE: Canonical unit label for the ratio. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Paris!D44:CP44
        Layout: series
        Value type: float

    Examples:
        compute_scenario_primary_expenditure_pct_gdp(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_PRIMARY_EXPENDITURE_PCT_GDP_PARIS:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

