def compute_scenario_primary_expenditure_pct_gdp(ctx=None, *, inputs=None) -> Records:
    """Compute primary expenditure as a percentage of GDP for a specific climate scenario.

    Returns TIME_PERIOD and OBS_VALUE records representing primary expenditure-to-GDP ratios for the High climate scenario.
    Each record corresponds to a column in the High scenario sheet, mapping a TIME_PERIOD column header to its OBS_VALUE cell.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year for the observation.
                - OBS_VALUE: Primary expenditure as a percentage of nominal GDP.
            Optional record fields:
                - UNIT_MEASURE: Unit of measure for the observation. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: High!D44:CP44
        Layout: series
        Value type: float

    Examples:
        compute_scenario_primary_expenditure_pct_gdp(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_PRIMARY_EXPENDITURE_PCT_GDP_HIGH:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

