def compute_scenario_primary_expenditure_pct_gdp(ctx=None, *, inputs=None) -> Records:
    """Compute the primary expenditure as a percentage of GDP for the Hot climate scenario.

    Returns a sequence of records with the primary expenditure-to-GDP ratio for the Hot scenario over the projection horizon.
    Each record maps to a column in the 'Hot' worksheet, where TIME_PERIOD corresponds to the year and OBS_VALUE to the primary expenditure as percent of GDP.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Projection year.
                - OBS_VALUE: Primary expenditure as a percentage of GDP.
            Optional record fields:
                - UNIT_MEASURE: Unit of measurement, always expressed as a percentage of GDP. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Hot!D44:CP44
        Layout: series
        Value type: float

    Examples:
        compute_scenario_primary_expenditure_pct_gdp(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_PRIMARY_EXPENDITURE_PCT_GDP_HOT:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

