def compute_scenario_interest_expenditure_pct_gdp(ctx=None, *, inputs=None) -> Records:
    """Retrieve projected interest expenditure as a percentage of GDP under the Hot climate scenario.

    Returns a sequence of records with annual interest expenditure (% of GDP) for the Hot scenario.
    Each record corresponds to one cell in the Hot sheet data range D43:CP43, keyed by year.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the projection.
                - OBS_VALUE: Interest expenditure expressed as a percentage of nominal GDP.
            Optional record fields:
                - UNIT_MEASURE: Unit of the observation value. If supplied, expected value: "PC_GDP".

    Source binding:
        Workbook range: Hot!D43:CP43
        Layout: series
        Value type: float

    Examples:
        compute_scenario_interest_expenditure_pct_gdp(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_INTEREST_EXPENDITURE_PCT_GDP_HOT:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

