def compute_scenario_real_gdp_level_index(ctx=None, *, inputs=None) -> Records:
    """Compute the projected real GDP level index for the Paris climate scenario over the full time horizon.

    Returns a series of annual real GDP level index values (actuals and projections) for the Paris climate-change scenario.
    Each record corresponds to one column in the Paris worksheet, using the header row for TIME_PERIOD and the data row for OBS_VALUE.

    Args:
        ctx (EvalContext | None): Existing evaluation context, if available.
        inputs (dict[str, object] | None): Optional input map when ctx is omitted.

    Returns:
        Records: Computed output records.
            Required record fields:
                - TIME_PERIOD: Calendar year of the observation.
                - OBS_VALUE: Real GDP level index value for the given year.
            Optional record fields:
                - UNIT_MEASURE: Unit of measure for the observation value. If supplied, expected value: "INDEX".

    Source binding:
        Workbook range: Paris!D14:CP14
        Layout: series
        Value type: float

    Examples:
        compute_scenario_real_gdp_level_index(ctx=ctx)
    """
    if ctx is None:
        ctx = make_context(inputs)
    elif inputs is not None:
        warnings.warn("inputs will be ignored because ctx was provided", UserWarning, stacklevel=2)
    measure_field = 'OBS_VALUE'
    include_address = False
    records: Records = []
    for address, static_record in _OUTPUT_LEAVES_SCENARIO_REAL_GDP_LEVEL_INDEX_PARIS:
        record = dict(static_record)
        try:
            record[measure_field] = xl_cell(ctx, address)
        except XlErrorException as _xl_err:
            record[measure_field] = _xl_err.code
        if include_address:
            record["address"] = address
        records.append(record)
    return records

